queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?testname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTests ?child ; p:hasDiagnostic_Centers ?parent . } GROUP BY ?child }
  ?child p:TestName ?testname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Diagnostic_Centers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?testname WHERE {
  ?diagnostic_centers_tests a :Diagnostic_Centers_Tests .
  ?tests a :Tests .
  ?diagnostic_centers_tests p:hasTests ?tests .
  ?diagnostic_centers a :Diagnostic_Centers .
  ?diagnostic_centers_tests p:hasDiagnostic_Centers ?diagnostic_centers .
  ?diagnostic_centers p:name ?name .
  ?tests p:TestName ?testname .
} }
  collective: { SELECT ?testname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTests ?child ; p:hasDiagnostic_Centers ?parent . } GROUP BY ?child }
  ?child p:TestName ?testname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Diagnostic_Centers } }
  FILTER(?nf = ?total)
} }
}
